<template>
	<view :class="className" :style="{ height: height, width: width, marginTop: marginTop, }">
		<l-echart ref="chart" @finished="init"></l-echart>
	</view>
</template>

<script>
	import * as echarts from 'echarts'
	//е…ЁйғЁз”өжңәзҠ¶жҖҒз»ҹи®Ў
	export default {
		name: 'basic_line_chart',
		props: {
			className: {
				type: String,
				default: 'chart'
			},
			width: {
				type: String,
				default: '100%'
			},
			height: {
				type: String,
				default: '100px'
			},
			autoResize: {
				type: Boolean,
				default: true
			},


			marginTop: {
				type: String,
				default: '10px'
			},
			//ж ҮзӮ№ж•°жҚ®
			legendData: {
				type: Array,
				default: () => [],
			},
			//жЁӘиҪҙеқҗж Ү
			xAxisData: {
				type: Array,
				default: () => [],
			},
			//зәөиҪҙеқҗж ҮеҖј
			series: {
				type: Array,
				default: () => [],
			},
			dayMonth: {
				type: Array,
				default: () => [],
			},
			__that: {
				type: Object,
				default: () => {
					return {};
				},
			},

			//   chartData: {
			//     type: Object,
			//     required: true
			//   }
		},
		data() {
			return {
				myChart: null,
				option: {
					tooltip: {
						trigger: 'axis',
						axisPointer: {
							type: 'shadow'
						}
					},
					legend: {
						bottom: '5%',
						// right: 'center',
						// icon: 'rect',//еҪўзҠ¶  зұ»еһӢеҢ…жӢ¬ circleпјҢrect,lineпјҢroundRectпјҢtriangleпјҢdiamondпјҢpinпјҢarrowпјҢnone
						itemWidth: 8, // и®ҫзҪ®е®ҪеәҰ
						itemHeight: 8, // и®ҫзҪ®й«ҳеәҰ
						// itemGap: 40, // и®ҫзҪ®дёӨдёӘlegendд№Ӣй—ҙзҡ„й—ҙи·қ
						// data:this.legendData,
						data: [{
								name: 'иүҜеҘҪ', // иҝҷдёӘnameйңҖиҰҒе’Ң series йҮҢйқўзҡ„ name еҜ№еә”иө·жқҘ
								// textStyle: {
								// 	color: '#2DC3FB' // еҚ•зӢ¬и®ҫзҪ®жҹҗдёҖдёӘеӣҫеҲ—зҡ„йўңиүІ
								// }
							},
							{
								name: 'жӯЈеёё', // иҝҷдёӘnameйңҖиҰҒе’Ң series йҮҢйқўзҡ„ name еҜ№еә”иө·жқҘ
								// textStyle: {
								// 	color: '#FDD43C' // еҚ•зӢ¬и®ҫзҪ®жҹҗдёҖдёӘеӣҫеҲ—зҡ„йўңиүІ
								// }
							},
							{
								name: 'е…іжіЁ', // иҝҷдёӘnameйңҖиҰҒе’Ң series йҮҢйқўзҡ„ name еҜ№еә”иө·жқҘ
								// textStyle: {
								// 	color: '#FDD43C' // еҚ•зӢ¬и®ҫзҪ®жҹҗдёҖдёӘеӣҫеҲ—зҡ„йўңиүІ
								// }
							},
							{
								name: 'й«ҳйЈҺйҷ©', // иҝҷдёӘnameйңҖиҰҒе’Ң series йҮҢйқўзҡ„ name еҜ№еә”иө·жқҘ
								// textStyle: {
								// 	color: '#FDD43C' // еҚ•зӢ¬и®ҫзҪ®жҹҗдёҖдёӘеӣҫеҲ—зҡ„йўңиүІ
								// }
							}
						]

					},
					xAxis: {
						type: 'category',
						data: this.xAxisData,
						// data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
					},
					yAxis: {
						type: 'value'
					},
					radius: '90%',
					series: this.series,
					// series: [

					// 	{
					// 		name: 'иүҜеҘҪ',
					// 		data: [140, 230, 274, 218, 135, 157, 240],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'жӯЈеёё',
					// 		data: [130, 230, 234, 228, 135, 147, 260],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'е…іжіЁ',
					// 		data: [110, 230, 224, 218, 165, 147, 270],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'й«ҳйЈҺйҷ©',
					// 		data: [100, 230, 214, 218, 135, 147, 260],
					// 		type: 'line'
					// 	},



					// ]
				},
			}
		},
		mounted() {
			
			this.$nextTick(() => {
				this.$refs.chart.init(echarts, chart => {
					chart.setOption(this.option);
				});
			})
		},
		beforeDestroy() {
			if (!this.chart) {
				return
			}
			this.chart.dispose()
			this.chart = null
		},
		watch: {
			legendData(newVal) {

				this.option.legend.data = newVal;

				this.$refs.chart.setOption(this.option)
			},
			xAxisData(newVal) {

				this.option.xAxis.data = newVal;

				this.$refs.chart.setOption(this.option)
			},
			series(newVal) {

				this.option.series = newVal;

				this.$refs.chart.setOption(this.option)
			},

		},
		methods: {
			async init() {
				const chart = await this.$refs.chart.init(echarts);
				if (this.option.color && this.option.color.length <= 0) {
					delete this.option['color']
				}
				chart.setOption(this.option)
				var that = this;
				chart.on('click', params => {
					console.log('зӮ№еҮ»дәӢд»¶и§ҰеҸ‘2пјҡ', params);
					let index = params.dataIndex;
                   let time = that.dayMonth[index];
					// uni.$emit('djBarClick', index);
					this.$emit('djTimeClick', time);
					// еӨ„зҗҶзӮ№еҮ»еӣһи°ғзҡ„дёҡеҠЎйҖ»иҫ‘
				});



			},

		}
	}
</script>